/**
 * EnemySystem — Enemy template registry, encounter generation, and instance creation.
 * All enemy definitions are loaded from enemies.json.
 *
 * @module EnemySystem
 */

import DebugLog from '../debug/DebugLog.js';
import ENEMIES_DATA from '../data/enemies.json';
import { createRNG, rollRange } from '../utils/RNG.js';
import CharacterSystem from './CharacterSystem.js';

let _instanceCounter = 0;

const EnemySystem = {
  _enemies: ENEMIES_DATA,

  /**
   * Get an enemy template by id.
   * @param {string} id
   * @returns {object|null}
   */
  getEnemyById(id) {
    return this._enemies.find(e => e.id === id) ?? null;
  },

  /**
   * Get all enemy templates.
   * @returns {object[]}
   */
  getAll() {
    return this._enemies;
  },

  /**
   * Generate a random encounter for a given region level and biome.
   * @param {number} regionLevel
   * @param {string} [biome='forest']
   * @param {ReturnType<import('../utils/RNG.js').createRNG>|null} [rng]
   * @returns {object[]} Array of combat-ready enemy instances
   */
  generateEncounter(regionLevel, biome = 'forest', rng = null) {
    const r = rng ?? createRNG(Date.now());
    // Filter enemies appropriate for this region level (±3 levels)
    const eligible = this._enemies.filter(e =>
      !e.isBoss &&
      Math.abs(e.level - regionLevel) <= 3 &&
      (e.biomes.includes(biome) || e.biomes.includes('any'))
    );
    if (!eligible.length) {
      // Fallback: orc_grunt
      eligible.push(this.getEnemyById('orc_grunt') ?? this._enemies[0]);
    }
    // 2-4 enemies
    const count = 2 + Math.floor(r.nextFloat() * 3);
    const enemies = [];
    for (let i = 0; i < count; i++) {
      const template = eligible[Math.floor(r.nextFloat() * eligible.length)];
      enemies.push(this.createInstance(template.id, regionLevel, r));
    }
    return enemies;
  },

  /**
   * Create a combat-ready enemy instance, optionally scaled to a given level.
   * @param {string} enemyId
   * @param {number|null} [level]
   * @param {ReturnType<import('../utils/RNG.js').createRNG>|null} [rng]
   * @returns {object|null}
   */
  createInstance(enemyId, level = null, rng = null) {
    const template = this.getEnemyById(enemyId);
    if (!template) {
      DebugLog.warn(`[enemy] Unknown enemy id: ${enemyId}`);
      return null;
    }
    const r = rng ?? createRNG(Date.now() + _instanceCounter);
    const effectiveLevel = level ?? template.level;
    const levelScale = effectiveLevel / Math.max(template.level, 1);

    _instanceCounter++;
    const id = `enemy_${enemyId}_${_instanceCounter}`;

    // Scale HP and stats
    const hp = Math.round(template.baseHP * levelScale + effectiveLevel * 3);
    const armor = Math.round(template.baseArmor * levelScale);

    return {
      id,
      baseId: enemyId,
      name: template.name,
      isPlayer: false,
      isEnemy: true,
      level: effectiveLevel,
      hp,
      maxHP: hp,
      mana: 20 + effectiveLevel * 5,
      maxMana: 20 + effectiveLevel * 5,
      attributes: { ...template.attributes },
      armor,
      weaponDamage: template.weaponDamage ?? { min: 5, max: 9 },
      aiProfile: template.aiProfile ?? 'aggressive',
      skills: template.skills ?? [],
      statusEffects: [],
      isDefending: false,
      isConscious: true,
      skillCooldowns: {},
      xpReward: template.xpReward + (effectiveLevel - template.level) * 3,
      loot: template.loot ?? [],
      specialTraits: template.specialTraits ?? [],
    };
  },

  /**
   * Roll loot drops for a defeated enemy instance.
   * @param {object} enemyInstance
   * @param {ReturnType<import('../utils/RNG.js').createRNG>|null} [rng]
   * @returns {{ items: Array<{itemId: string, quantity: number}>, gold: number }}
   */
  rollLoot(enemyInstance, rng = null) {
    const r = rng ?? createRNG(Date.now());
    const drops = [];
    for (const entry of (enemyInstance.loot ?? [])) {
      if (r.nextFloat() < entry.chance) {
        drops.push({ itemId: entry.itemId, quantity: 1 });
      }
    }
    // Gold drop: level * (2..6) gold
    const gold = rollRange(r, enemyInstance.level * 2, enemyInstance.level * 6);
    return { items: drops, gold };
  },
};

// ─── Debug exposure ───────────────────────────────────────────────────────────

if (typeof window !== 'undefined') {
  window.__enemySystem = EnemySystem;
}

export default EnemySystem;
